protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9: HasIndex throws for Cosmos entities — removed.
    // Manage indexing via the container's indexing policy in Azure Portal/Bicep.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // EF Core 9: Default discriminator property renamed from "Discriminator" to "$type".
    // Preserve "Discriminator" so existing 500K documents and direct SQL queries still work.
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // EF Core 9: id values changed from "Product|123" to "123".
    // Preserve the old compound format so existing documents remain accessible.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

