using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    // EF Core 9 Cosmos: sync I/O (ToList, SaveChanges, etc.) now throws — use async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (not c.$type)
        // because we configured HasDiscriminator<string>("Discriminator") in the model.
        var sql = "SELECT VALUE c FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

